+    #[test]
+    fn config_default_fields() {
+        let c = WsPtyBridgeConfig::default();
+        assert_eq!(c.bind_addr, SocketAddr::from(([127, 0, 0, 1], 9231)));
+        assert!(c.args.is_empty());
+        assert_eq!(c.term, "xterm-256color");
